import { connection } from 'next/server'

export default async function Timestamp() {
  // `connection()` tells Next.js this component is dynamic without using
  // cookies/headers/draftMode. In production builds, this opts the route out
  // of static prerendering so the timestamp is evaluated per-request.
  await connection()

  const now = new Date()
  const formatted = now.toLocaleString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    timeZoneName: 'short',
    hourCycle: 'h23',
  })

  const iso = now.toISOString()

  return (
    <div>
      <p>
        <strong>Server timestamp:</strong> {formatted}
      </p>
      <p>
        <strong>ISO 8601:</strong> <code>{iso}</code>
      </p>
      <p>
        <strong>Unix epoch (ms):</strong>{' '}
        <code>{now.getTime().toLocaleString()}</code>
      </p>
    </div>
  )
}

import Timestamp from './timestamp'

export default function Home() {
  return (
    <main>
      <h1>Server Timestamp</h1>
      <Timestamp />
    </main>
  )
}
